INSERT INTO diagnoses (id, report_id, passed, created_at) VALUES ('8f35b2df-0f8b-4dd5-905e-ae58d36b69d4', 'f8d92b49-7b80-40e7-9966-fd183e162b95', FALSE, '2026-07-14T11:40:39.842588+00');
INSERT INTO diagnosis_issues (id, diagnosis_id, dimension, metric, value, threshold, reason, suggestion) VALUES ('7847d4c7-99d3-4327-be72-16392261ed60', '1188ac41-5996-47a4-acff-138e1e2fd485', '工作满意度', 'kmo', 0.5, 0.6, 'KMO值仅为0.5，低于可接受阈值0.6，表明变量间的偏相关性较弱，不适合进行因子分析。可能原因包括：该维度题目数量过少（例如少于3题），或题目间共同度较低、存在较多特异性方差，导致整体结构效度不足。', '建议增加该维度的题目数量（至少3-5题），并确保题目内容紧密围绕工作满意度核心概念；同时可删除部分相关性极低的题目，或重新审视题目措辞以提高内部一致性。若样本量较小，可考虑扩大样本。');
INSERT INTO diagnosis_issues (id, diagnosis_id, dimension, metric, value, threshold, reason, suggestion) VALUES ('852f49ff-a144-406a-9ac4-8ed205aeb5e8', '1188ac41-5996-47a4-acff-138e1e2fd485', '职业发展', 'kmo', 0.5, 0.6, 'KMO值为0.5，低于可接受阈值0.6，表明变量间偏相关性较弱，因子分析适用性不足。可能原因包括：该维度题目数量偏少，或题目内容存在歧义、重复度低，导致变量间无法提取公共因子。', '建议优化或扩充该维度题目，确保题目能充分覆盖职业发展的不同方面（如晋升机会、培训支持、职业规划等）；同时进行项目分析，剔除区分度低或与其他题目相关性过弱的题目。如果条件允许，可重新收集数据并检验结构效度。');
INSERT INTO diagnosis_issues (id, diagnosis_id, dimension, metric, value, threshold, reason, suggestion) VALUES ('4c457fc0-11ec-445c-ac71-24a0d6f8e928', 'b54e294b-9cd0-4196-b131-da3e55787d2c', '工作满意度', 'kmo', 0.5, 0.6, 'KMO值为0.5，低于0.6的可接受标准，表明该维度内题项之间的偏相关性较强，变量间共同方差较少，可能由于样本量不足、题项间相关性较低或存在无关题项导致因子分析效果不佳。', '建议增加样本量（如达到题项数的5-10倍），检查并删除与其他题项相关性过低的题目，或重新评估题项内容是否准确反映工作满意度构念，可尝试探索性因子分析以优化题项结构。');
INSERT INTO diagnosis_issues (id, diagnosis_id, dimension, metric, value, threshold, reason, suggestion) VALUES ('2940cb9a-0503-4a81-9513-56f54216cea4', 'b54e294b-9cd0-4196-b131-da3e55787d2c', '职业发展', 'kmo', 0.5, 0.6, 'KMO值为0.5，低于0.6的可接受标准，说明该维度内题项间的共同因素较少，可能由于题目数量不足、维度内部一致性较低或存在测量误差较大的题目影响因子提取。', '建议增加样本量，对维度内题项进行项目分析，删除因子载荷较低或交叉载荷严重的题目，或根据理论考虑增加新的测量条目以提高维度结构清晰度。');
INSERT INTO diagnosis_issues (id, diagnosis_id, dimension, metric, value, threshold, reason, suggestion) VALUES ('b67ef6f9-cf96-4643-bd5c-b7a69195d504', '6e29c99c-cbb5-43da-8b2a-7e797b8cb117', '', 'cumulative_variance', 0, 0, '命中翻车点 P07：未报累计方差解释率', '因子分析应报告累计方差解释率，以说明公因子对原变量的解释能力。请补充该指标。');
INSERT INTO diagnosis_issues (id, diagnosis_id, dimension, metric, value, threshold, reason, suggestion) VALUES ('ad015db1-06ef-4f36-b94d-3cb6a99e7642', '3e270a3a-7c5e-48a3-8c54-6463cd3d2f87', '', 'cumulative_variance', 0, 0, '命中翻车点 P07：未报累计方差解释率', '因子分析应报告累计方差解释率，以说明公因子对原变量的解释能力。请补充该指标。');
INSERT INTO diagnosis_issues (id, diagnosis_id, dimension, metric, value, threshold, reason, suggestion) VALUES ('73d8892b-9964-49f8-95d2-43653dd2f08c', '14ab0551-813a-4ed1-8b12-1c51f9b53139', '', 'cumulative_variance', 0, 0, '命中翻车点 P07：未报累计方差解释率', '因子分析应报告累计方差解释率，以说明公因子对原变量的解释能力。请补充该指标。');
INSERT INTO diagnosis_issues (id, diagnosis_id, dimension, metric, value, threshold, reason, suggestion) VALUES ('28b48fc9-6f13-40ad-8062-b3434ecf24c9', '336d58cd-0c6f-4f60-a764-24650b3bc79b', '', 'reverse_items', 0, 0, '命中翻车点 P01：反向题未反转', '存在反向题但未做反向计分，会导致 α 偏低甚至负值。请在数据预处理阶段反转反向题（如 6 减去原值），再重算信度。');
INSERT INTO diagnosis_issues (id, diagnosis_id, dimension, metric, value, threshold, reason, suggestion) VALUES ('b5c985e4-b1ce-45ed-be90-eff25c978132', '336d58cd-0c6f-4f60-a764-24650b3bc79b', '', 'kmo', 0, 0, '命中翻车点 P04：KMO<0.5 仍强行做 EFA', 'KMO 低于 0.5 时数据不适合做因子分析，强行 EFA 会导致因子结构不稳定。建议先检查变量间相关性，或增加样本/调整题项后重测 KMO。');
INSERT INTO diagnosis_issues (id, diagnosis_id, dimension, metric, value, threshold, reason, suggestion) VALUES ('8ba2d340-94f9-48ef-8111-77bca6f73f30', '336d58cd-0c6f-4f60-a764-24650b3bc79b', '', 'cumulative_variance', 0, 0, '命中翻车点 P07：未报累计方差解释率', '因子分析应报告累计方差解释率，以说明公因子对原变量的解释能力。请补充该指标。');
INSERT INTO diagnosis_issues (id, diagnosis_id, dimension, metric, value, threshold, reason, suggestion) VALUES ('89065e91-f9b1-4f1b-b927-6cc608b34ef4', '336d58cd-0c6f-4f60-a764-24650b3bc79b', '工作满意度', 'kmo', 0.5, 0.5, 'KMO值刚好处于临界下限，表明题项间共同方差偏低。可能是因为部分题项与其他题项相关性较弱，或样本量不足导致变量间关联性不稳定。', '建议增加样本量（当前样本量可能过小），同时检查每个题项与其他题项的相关系数，删除相关系数低于0.3的题项后重新计算KMO，或考虑调整量表结构。');
INSERT INTO diagnosis_issues (id, diagnosis_id, dimension, metric, value, threshold, reason, suggestion) VALUES ('4d304562-7dcb-43a3-88c2-ae16888e832b', '336d58cd-0c6f-4f60-a764-24650b3bc79b', '人际关系', 'alpha', 0, 0.7, 'Cronbach''s α为0，表明题项间内部一致性问题严重。可能原因包括：反向题未正确计分导致题项间负相关、题项表述歧义或与维度定义不符、题目数量过少（如不足3题）、或样本存在异常值。', '首先检查数据预处理是否完成反向题反转（如将反向题分数用最大值+1减去原值）；其次计算题项间相关矩阵，识别并删除与其他题项负相关或相关系数极低的题目；若题项数少于3个，需补充题目；同时检查是否有异常值或缺失值影响。');
INSERT INTO diagnosis_issues (id, diagnosis_id, dimension, metric, value, threshold, reason, suggestion) VALUES ('0abd4362-18a5-4e94-b4fa-5ed1e209449d', '336d58cd-0c6f-4f60-a764-24650b3bc79b', '人际关系', 'kmo', 0, 0.5, 'KMO值为0，表明变量间几乎无共同方差，数据完全不适合做因子分析。通常因题项之间相互独立（相关系数接近0）或样本量严重不足导致。', '检查题项间相关系数矩阵，若大部分相关系数<0.1则需要重新设计量表；如果样本量极小（如<30），需收集更多样本；若题项间存在明显负相关，需检查反向题处理。在问题解决前不建议进行因子分析。');
INSERT INTO diagnosis_issues (id, diagnosis_id, dimension, metric, value, threshold, reason, suggestion) VALUES ('691d0d95-25d6-40e1-b7b3-7927ddf3da10', '336d58cd-0c6f-4f60-a764-24650b3bc79b', '人际关系', 'bartlett_p', 1, 0.05, 'Bartlett球形检验p=1.0，完全不显著，说明相关矩阵为单位矩阵，变量之间相互独立，无法提取公因子。原因与KMO=0相同，即题项间缺乏相关性。', '与KMO问题同步解决：确保反向题正确反转，检查题项语义是否与维度一致，必要时删除或修改无相关性的题项，并增加样本量后重测。');
INSERT INTO diagnosis_issues (id, diagnosis_id, dimension, metric, value, threshold, reason, suggestion) VALUES ('1e3ec16f-4740-437b-8f74-49e3e4d76ec1', '336d58cd-0c6f-4f60-a764-24650b3bc79b', '工作感受', 'alpha', 0, 0.7, 'Cronbach''s α为0，表明该维度题项之间内部一致性极差。常见原因包括反向题未反转导致负相关、题项内容偏离维度定义、或题目数量过少。', '核查数据中是否存在反向题并确认已反转；计算题项间相关系数，删除负相关或极低相关的题目；考虑增加2-3个与“工作感受”内涵一致的题目以提高信度。');
INSERT INTO diagnosis_issues (id, diagnosis_id, dimension, metric, value, threshold, reason, suggestion) VALUES ('40b63673-3462-4b79-9b79-0b554eac42bd', '336d58cd-0c6f-4f60-a764-24650b3bc79b', '工作感受', 'kmo', 0, 0.5, 'KMO为0，说明题项间无共同方差，无法进行因子分析。可能由于题项间完全独立，或样本量不足以估计相关结构。', '建议先检查每个题项与其他题项的相关系数，若多数接近0则需重新设计量表；若样本量不足，则扩大样本量至题项数的10倍以上。');
INSERT INTO diagnosis_issues (id, diagnosis_id, dimension, metric, value, threshold, reason, suggestion) VALUES ('448c82fb-aac0-4a44-bc81-1847a50b667b', '336d58cd-0c6f-4f60-a764-24650b3bc79b', '工作感受', 'bartlett_p', 1, 0.05, 'Bartlett检验不显著，进一步验证了变量间不存在相关性，原因与KMO相同。', '与上述KMO问题一并处理：确保数据预处理正确，检查题项质量，增加样本或修改量表。');
INSERT INTO diagnosis_issues (id, diagnosis_id, dimension, metric, value, threshold, reason, suggestion) VALUES ('62ae881a-cc23-4f7a-b541-c149a3c69291', '336d58cd-0c6f-4f60-a764-24650b3bc79b', '薪酬福利', 'alpha', 0, 0.7, '内部一致性信度为0，提示题项间可能存在负相关或完全无关。可能原因是该维度包含反向题但未反转，或题项表述不一致。', '确认所有反向题是否已正确反转；计算题项间相关矩阵，若出现负相关则重点检查反向题；若题项数不足3个，考虑增加题目。');
INSERT INTO diagnosis_issues (id, diagnosis_id, dimension, metric, value, threshold, reason, suggestion) VALUES ('3602fad4-4061-478b-909d-a0adcee2807f', '336d58cd-0c6f-4f60-a764-24650b3bc79b', '薪酬福利', 'kmo', 0, 0.5, 'KMO值为0，数据不适合因子分析，通常因变量间独立或样本过小引起。', '检查样本量是否足够（建议>100），并计算题项间相关系数；若相关系数普遍偏低，需重新审视量表题项。');
INSERT INTO diagnosis_issues (id, diagnosis_id, dimension, metric, value, threshold, reason, suggestion) VALUES ('1c5d4e1e-f3d0-45a9-b86a-8ef0776bbd8a', '336d58cd-0c6f-4f60-a764-24650b3bc79b', '薪酬福利', 'bartlett_p', 1, 0.05, 'Bartlett检验p=1.0，说明相关矩阵为单位矩阵，无法提取因子。', '与KMO问题同步解决，确保题项间存在一定的相关性后再进行因子分析。');
INSERT INTO diagnosis_issues (id, diagnosis_id, dimension, metric, value, threshold, reason, suggestion) VALUES ('ab41704b-34c6-4b51-a3fb-e48102f88f4c', '336d58cd-0c6f-4f60-a764-24650b3bc79b', '职业发展', 'alpha', 0, 0.7, 'α为0，内部一致性差。可能由于反向题未处理、题项间方向不一、或题目内容无法反映同一构念。', '反向题反转后重算信度；若仍为0，则逐题检查题项是否属于同一维度，考虑删除或修改。');
INSERT INTO diagnosis_issues (id, diagnosis_id, dimension, metric, value, threshold, reason, suggestion) VALUES ('dcfcffd7-d194-49e0-a43c-06dfb91c6a10', '336d58cd-0c6f-4f60-a764-24650b3bc79b', '职业发展', 'kmo', 0, 0.5, 'KMO=0，变量间无共同方差。', '检查样本量和题项相关性，剔除无相关题项。');
INSERT INTO diagnosis_issues (id, diagnosis_id, dimension, metric, value, threshold, reason, suggestion) VALUES ('4f246fdc-61c5-46a4-939e-20f21aa8b617', '336d58cd-0c6f-4f60-a764-24650b3bc79b', '职业发展', 'bartlett_p', 1, 0.05, 'Bartlett检验不显著，变量间独立。', '加强题项相关性构建，如修改题项措辞使其更聚焦于同一构念。');
INSERT INTO diagnosis_issues (id, diagnosis_id, dimension, metric, value, threshold, reason, suggestion) VALUES ('4dc0cdea-6205-4191-a40b-4de0642b71c4', '336d58cd-0c6f-4f60-a764-24650b3bc79b', '工作压力', 'alpha', 0, 0.7, '内部一致性信度为0，可能因反向题未反转或题项间相关系数过低。', '检查反向题反转情况；计算题项间相关系数，删除低相关题项；若题项数<3，需补充。');
INSERT INTO diagnosis_issues (id, diagnosis_id, dimension, metric, value, threshold, reason, suggestion) VALUES ('2746be8d-572d-43a5-82e3-fc83c35beb7c', '336d58cd-0c6f-4f60-a764-24650b3bc79b', '工作压力', 'kmo', 0, 0.5, 'KMO=0，不适合因子分析。', '增加样本量并优化题项。');
INSERT INTO diagnosis_issues (id, diagnosis_id, dimension, metric, value, threshold, reason, suggestion) VALUES ('06e53ef8-aee6-42a1-8e68-19400b9b0577', '336d58cd-0c6f-4f60-a764-24650b3bc79b', '工作压力', 'bartlett_p', 1, 0.05, 'Bartlett检验不显著。', '与KMO问题一同处理。');
INSERT INTO diagnosis_issues (id, diagnosis_id, dimension, metric, value, threshold, reason, suggestion) VALUES ('fdcb8105-162d-4875-bf74-ed89eac8321a', '336d58cd-0c6f-4f60-a764-24650b3bc79b', '组织认同', 'kmo', 0.5, 0.5, 'KMO值为0.5，处于临界下限，表明题项间共同度不足。可能由于部分题项与其他题项相关性较弱或样本量有限。', '建议增加样本量，并删除与维度内其他题项相关系数低于0.3的题目，以提高KMO值至0.6以上。');
INSERT INTO diagnosis_issues (id, diagnosis_id, dimension, metric, value, threshold, reason, suggestion) VALUES ('7d64c1d3-5415-4f2a-89a7-7b94c03fe4b7', '336d58cd-0c6f-4f60-a764-24650b3bc79b', '工作生活平衡', 'alpha', 0, 0.7, 'α为0，内部一致性极差，常见于反向题未正确处理或题项间缺乏相关性。', '检查反向题反转情况，计算相关系数并删除无关题项。');
INSERT INTO diagnosis_issues (id, diagnosis_id, dimension, metric, value, threshold, reason, suggestion) VALUES ('2e6a35fe-184a-4d37-8d8c-34a4b5023547', '336d58cd-0c6f-4f60-a764-24650b3bc79b', '工作生活平衡', 'kmo', 0, 0.5, 'KMO=0，数据不适合因子分析。', '检查样本量和题项质量。');
INSERT INTO diagnosis_issues (id, diagnosis_id, dimension, metric, value, threshold, reason, suggestion) VALUES ('180b74ab-95a4-4213-bbd6-476ea4734f95', '336d58cd-0c6f-4f60-a764-24650b3bc79b', '工作生活平衡', 'bartlett_p', 1, 0.05, 'Bartlett检验不显著，变量间独立。', '与KMO问题一起解决。');
INSERT INTO diagnosis_issues (id, diagnosis_id, dimension, metric, value, threshold, reason, suggestion) VALUES ('15370b54-dc11-43a1-b1fc-75d06f408445', 'd623e39a-5529-4d3c-ab00-15884a3831c6', '', 'reverse_items', 0, 0, '命中翻车点 P01：反向题未反转', '存在反向题但未做反向计分，会导致 α 偏低甚至负值。请在数据预处理阶段反转反向题（如 6 减去原值），再重算信度。');
INSERT INTO diagnosis_issues (id, diagnosis_id, dimension, metric, value, threshold, reason, suggestion) VALUES ('52cc772b-1de2-413c-b1e9-3da34c5ac9c4', 'd623e39a-5529-4d3c-ab00-15884a3831c6', '', 'kmo', 0, 0, '命中翻车点 P04：KMO<0.5 仍强行做 EFA', 'KMO 低于 0.5 时数据不适合做因子分析，强行 EFA 会导致因子结构不稳定。建议先检查变量间相关性，或增加样本/调整题项后重测 KMO。');
INSERT INTO diagnosis_issues (id, diagnosis_id, dimension, metric, value, threshold, reason, suggestion) VALUES ('e648577f-93f2-4b5e-9ff7-274fa93104ba', 'd623e39a-5529-4d3c-ab00-15884a3831c6', '', 'cumulative_variance', 0, 0, '命中翻车点 P07：未报累计方差解释率', '因子分析应报告累计方差解释率，以说明公因子对原变量的解释能力。请补充该指标。');
INSERT INTO diagnosis_issues (id, diagnosis_id, dimension, metric, value, threshold, reason, suggestion) VALUES ('e7fb04c6-07d0-4880-96d0-15aedaa3a88f', 'd623e39a-5529-4d3c-ab00-15884a3831c6', '工作满意度', 'alpha', 0, 0.7, 'α值为0，表明题目间无任何内部一致性。可能原因：反向题未反转导致负相关被截断为0；或数据变异极小（所有被试回答相同或样本量过小）。', '检查数据预处理：确认所有反向题已正确反转（如6-原值）；查看每个题目的标准差，若为0则删除无效题目；确保样本量至少30-50以上，重新计算信度。');
INSERT INTO diagnosis_issues (id, diagnosis_id, dimension, metric, value, threshold, reason, suggestion) VALUES ('0afe461c-2fd4-4dc6-9c73-1aa21dade79a', 'd623e39a-5529-4d3c-ab00-15884a3831c6', '工作满意度', 'kmo', 0, 0.5, 'KMO为0，说明变量间偏相关系数极小，数据完全不适宜做因子分析。通常因变量间无相关或样本极端不足导致。', '先检查变量间Pearson相关系数，若多数接近0，需修订题目或重新收集数据；若样本量过小，需增加被试至至少100以上；同时检查数据录入错误。');
INSERT INTO diagnosis_issues (id, diagnosis_id, dimension, metric, value, threshold, reason, suggestion) VALUES ('3b058420-c7f7-4162-93e5-27b7ef76c255', 'd623e39a-5529-4d3c-ab00-15884a3831c6', '工作满意度', 'bartlett_p', 1, 0.05, 'Bartlett球形检验p=1.0，表明相关矩阵为单位矩阵，变量间完全独立。常见原因：题目无变异（所有回答相同）、样本量极低或错误编码。', '核实数据矩阵是否包含有效差异；检查是否误用常量数据；若样本量小于变量数，需扩充样本；重新运行描述统计确认变量方差。');
INSERT INTO diagnosis_issues (id, diagnosis_id, dimension, metric, value, threshold, reason, suggestion) VALUES ('edab4ceb-f89a-422f-9982-4a8b8ae32666', 'd623e39a-5529-4d3c-ab00-15884a3831c6', '人际关系', 'alpha', 0, 0.7, '同工作满意度维度，α=0表明内部一致性失效，可能是反向题未反转或数据无变异。', '检查反向题计分方向，确保所有题目计分方向一致；计算各题方差，剔除零方差题目；增加样本量后重算。');
INSERT INTO diagnosis_issues (id, diagnosis_id, dimension, metric, value, threshold, reason, suggestion) VALUES ('cdd5e333-aaad-4c4c-b421-c3573f97a1e1', 'd623e39a-5529-4d3c-ab00-15884a3831c6', '人际关系', 'kmo', 0, 0.5, 'KMO=0，变量间无共享方差，无法进行因子分析。原因同上。', '检查题目间相关性，改善题目设计或重新收集数据；若样本量过小，扩大样本至合理规模。');
INSERT INTO diagnosis_issues (id, diagnosis_id, dimension, metric, value, threshold, reason, suggestion) VALUES ('6aade1ab-0fe9-458a-9a3c-7743e786cd28', 'd623e39a-5529-4d3c-ab00-15884a3831c6', '人际关系', 'bartlett_p', 1, 0.05, 'p=1.0，数据不存在任何相关结构。可能因样本单一或数据录入格式错误。', '确认原始数据是否为数值型且包含足够变异；检查是否存在缺失值或异常值处理不当。');
INSERT INTO diagnosis_issues (id, diagnosis_id, dimension, metric, value, threshold, reason, suggestion) VALUES ('d2659d72-c955-46cb-94e7-bddd6e08b8a6', 'd623e39a-5529-4d3c-ab00-15884a3831c6', '工作感受', 'alpha', 0, 0.7, 'α=0，表明题目间无一致性。可能原因：反向题未反转或数据无变异。', '重新审查该维度题项是否有反向表述并正确反转；计算项目-总分相关，删除相关为负或极低的题项。');
INSERT INTO diagnosis_issues (id, diagnosis_id, dimension, metric, value, threshold, reason, suggestion) VALUES ('d1708c6c-07ef-4574-83e9-9e7e49d3f09c', 'd623e39a-5529-4d3c-ab00-15884a3831c6', '工作感受', 'kmo', 0, 0.5, 'KMO=0，不适合因子分析。原因同前。', '若相关矩阵对角元素远大于非对角，需修改量表设计；也可尝试删除低相关题目后再测KMO。');
INSERT INTO diagnosis_issues (id, diagnosis_id, dimension, metric, value, threshold, reason, suggestion) VALUES ('59cc6dd0-0f5e-4cc1-b752-9783e4bc1a0c', 'd623e39a-5529-4d3c-ab00-15884a3831c6', '工作感受', 'bartlett_p', 1, 0.05, 'Bartlett检验不显著，变量间独立。原因：数据无差异或样本量不足。', '核实样本量是否达到每题至少5-10倍的要求；检查是否所有题目答案相同。');
INSERT INTO diagnosis_issues (id, diagnosis_id, dimension, metric, value, threshold, reason, suggestion) VALUES ('a4d857e2-e039-4d0a-8e52-20df1458dbbd', 'd623e39a-5529-4d3c-ab00-15884a3831c6', '薪酬福利', 'alpha', 0, 0.7, 'α=0，内部一致性缺失。', '检查该维度题目是否包含反向题，确保反转正确；若题目数量过少（如≤2），建议增加题目。');
INSERT INTO diagnosis_issues (id, diagnosis_id, dimension, metric, value, threshold, reason, suggestion) VALUES ('23411105-bb93-43e6-89e6-5fbca09af74a', 'd623e39a-5529-4d3c-ab00-15884a3831c6', '薪酬福利', 'kmo', 0, 0.5, 'KMO=0，数据不适合因子分析。', '计算该维度题目的Spearman相关矩阵，若所有相关绝对值小于0.3，则需重新设计题目或调整施测。');
INSERT INTO diagnosis_issues (id, diagnosis_id, dimension, metric, value, threshold, reason, suggestion) VALUES ('2ec6b8a6-b8b5-4b8f-b66d-d5a09192b629', 'd623e39a-5529-4d3c-ab00-15884a3831c6', '薪酬福利', 'bartlett_p', 1, 0.05, 'p=1.0，无相关结构。', '检查是否有题项编码错误（如反向题未反转导致负相关被抵消）；若样本量<30，需扩充。');
INSERT INTO diagnosis_issues (id, diagnosis_id, dimension, metric, value, threshold, reason, suggestion) VALUES ('1ea2cabf-f60e-4e70-96ad-7805755bff67', 'd623e39a-5529-4d3c-ab00-15884a3831c6', '职业发展', 'alpha', 0, 0.7, 'α=0，信度极低。', '利用项目分析（如区分度）筛选题项；若全部题目方差为0，则数据无效，需重新收集。');
INSERT INTO diagnosis_issues (id, diagnosis_id, dimension, metric, value, threshold, reason, suggestion) VALUES ('23976b41-16b9-4bbf-b2d3-1e4b3c066bc4', 'd623e39a-5529-4d3c-ab00-15884a3831c6', '职业发展', 'kmo', 0, 0.5, 'KMO=0。', '尝试使用修正后的项目-总相关大于0.3的题目重新计算KMO；若仍低，需修订量表。');
INSERT INTO diagnosis_issues (id, diagnosis_id, dimension, metric, value, threshold, reason, suggestion) VALUES ('3db778be-45b3-4824-a50b-dce5a23cade0', 'd623e39a-5529-4d3c-ab00-15884a3831c6', '职业发展', 'bartlett_p', 1, 0.05, 'Bartlett检验未通过。', '检查数据是否来自单一个体或所有值相同；重新运行描述统计确认均值与标准差。');
INSERT INTO diagnosis_issues (id, diagnosis_id, dimension, metric, value, threshold, reason, suggestion) VALUES ('c5b8b7e6-21f6-41e1-9f41-e2899cd31056', 'd623e39a-5529-4d3c-ab00-15884a3831c6', '工作压力', 'alpha', 0, 0.7, 'α=0。', '检查是否存在极端值或录入错误；若为反向题未反转，则反转后重新计算。');
INSERT INTO diagnosis_issues (id, diagnosis_id, dimension, metric, value, threshold, reason, suggestion) VALUES ('68e49a98-5351-4eab-a86d-578100dec916', 'd623e39a-5529-4d3c-ab00-15884a3831c6', '工作压力', 'kmo', 0, 0.5, 'KMO=0。', '确保样本量至少为变量数的5倍；如果变量数>样本量，则需收集更多数据。');
INSERT INTO diagnosis_issues (id, diagnosis_id, dimension, metric, value, threshold, reason, suggestion) VALUES ('cc6ea701-546f-40e8-afb4-ad52f8da7614', 'd623e39a-5529-4d3c-ab00-15884a3831c6', '工作压力', 'bartlett_p', 1, 0.05, 'p=1.0。', '检查是否所有被试在本题组上只选择了同一选项；若是，则题目无效。');
INSERT INTO diagnosis_issues (id, diagnosis_id, dimension, metric, value, threshold, reason, suggestion) VALUES ('5093ee76-f22a-4d9d-b882-4749faab3aaf', 'd623e39a-5529-4d3c-ab00-15884a3831c6', '组织认同', 'alpha', 0, 0.7, 'α=0。', '检查该维度下题目是否均为正向表述，若有反向题请反转；同时检查样本量是否≥30。');
INSERT INTO diagnosis_issues (id, diagnosis_id, dimension, metric, value, threshold, reason, suggestion) VALUES ('6f017e73-8e25-4d6a-af3f-1562cffdf6c6', 'd623e39a-5529-4d3c-ab00-15884a3831c6', '组织认同', 'kmo', 0, 0.5, 'KMO=0。', '计算变量间相关系数矩阵，若大部分<0.1，建议修改量表或扩大样本。');
INSERT INTO diagnosis_issues (id, diagnosis_id, dimension, metric, value, threshold, reason, suggestion) VALUES ('eed544ed-55d3-4c76-9c7d-a02b30cdeb95', 'd623e39a-5529-4d3c-ab00-15884a3831c6', '组织认同', 'bartlett_p', 1, 0.05, 'p=1.0。', '确认数据是否因分列不当导致所有值相同；重新导入原始数据并检查格式。');
INSERT INTO diagnosis_issues (id, diagnosis_id, dimension, metric, value, threshold, reason, suggestion) VALUES ('c90a420f-db1c-496b-a677-57af2f2b3a2f', 'd623e39a-5529-4d3c-ab00-15884a3831c6', '工作生活平衡', 'alpha', 0, 0.7, 'α=0。', '使用SPSS或R的psych包计算信度时，请确认反向题已用''ReverseCode''函数处理；若仍为0，则数据不可信。');
INSERT INTO diagnosis_issues (id, diagnosis_id, dimension, metric, value, threshold, reason, suggestion) VALUES ('f1a84ad2-f465-4614-a20d-ff32695e80e6', 'd623e39a-5529-4d3c-ab00-15884a3831c6', '工作生活平衡', 'kmo', 0, 0.5, 'KMO=0。', '尝试删除该维度下与其他题目无相关的题项；若仅剩1题则不可做因子分析。');
INSERT INTO diagnosis_issues (id, diagnosis_id, dimension, metric, value, threshold, reason, suggestion) VALUES ('ed308257-3941-4eea-8453-7db3ee7fc778', 'd623e39a-5529-4d3c-ab00-15884a3831c6', '工作生活平衡', 'bartlett_p', 1, 0.05, 'p=1.0。', '检查是否因为样本量过小或数据为常数导致；建议收集至少100份有效问卷后重测。');
INSERT INTO diagnosis_issues (id, diagnosis_id, dimension, metric, value, threshold, reason, suggestion) VALUES ('ff0d333c-665b-4ef5-8566-f0161e554c32', 'a4c725f7-6fe1-4232-814b-74523f7eb923', '', 'reverse_items', 0, 0, '命中翻车点 P01：反向题未反转', '存在反向题但未做反向计分，会导致 α 偏低甚至负值。请在数据预处理阶段反转反向题（如 6 减去原值），再重算信度。');
INSERT INTO diagnosis_issues (id, diagnosis_id, dimension, metric, value, threshold, reason, suggestion) VALUES ('bd187b25-0019-445e-beb0-aeb2d1fd2f9b', 'a4c725f7-6fe1-4232-814b-74523f7eb923', '', 'kmo', 0, 0, '命中翻车点 P04：KMO<0.5 仍强行做 EFA', 'KMO 低于 0.5 时数据不适合做因子分析，强行 EFA 会导致因子结构不稳定。建议先检查变量间相关性，或增加样本/调整题项后重测 KMO。');
INSERT INTO diagnosis_issues (id, diagnosis_id, dimension, metric, value, threshold, reason, suggestion) VALUES ('ceb7be2a-f8d6-44e5-b612-eb63ecd16a6b', 'a4c725f7-6fe1-4232-814b-74523f7eb923', '', 'cumulative_variance', 0, 0, '命中翻车点 P07：未报累计方差解释率', '因子分析应报告累计方差解释率，以说明公因子对原变量的解释能力。请补充该指标。');
INSERT INTO diagnosis_issues (id, diagnosis_id, dimension, metric, value, threshold, reason, suggestion) VALUES ('3fb27195-ac69-4ffb-a898-c9d317ee7289', 'a4c725f7-6fe1-4232-814b-74523f7eb923', '工作满意度', 'alpha', 0, 0.7, 'Cronbach''s α 为 0.0，表明该维度内各条目之间完全不存在正相关，甚至可能因反向题未反转导致负相关被抵消。同时不排除数据录入错误、条目方差为零（如所有被试回答完全相同）或样本量过小（如 < 5）导致信度无法计算。', '1. 检查原始数据：确认该维度所有条目是否存在变异（即标准差 > 0）；2. 核对反向题的编码是否已正确反转（原值 → 6-原值）；3. 若样本量 < 30，建议补充样本至至少 50 人；4. 重算信度前，删除缺失值或常数条目。');
INSERT INTO diagnosis_issues (id, diagnosis_id, dimension, metric, value, threshold, reason, suggestion) VALUES ('59b3c897-30d2-48c6-a7ab-da179e8311b9', 'a4c725f7-6fe1-4232-814b-74523f7eb923', '工作满意度', 'kmo', 0, 0.5, 'KMO 为 0.0，说明变量间偏相关系数平方和远大于简单相关系数平方和，数据完全不适合做因子分析。常见原因包括：变量间几乎无线性相关（可能因反向题未反转导致符号错乱）、条目方差为零、或样本量极低（< 样本数 < 变量数）。', '1. 计算各条目间 Pearson 相关矩阵，若多数相关系数 < 0.1，需检查数据质量；2. 确保所有条目为非定值且量尺一致（如均使用 1-5 Likert）；3. 增加样本量至条目数的 5-10 倍；4. 在反转反向题后重新计算 KMO。');
INSERT INTO diagnosis_issues (id, diagnosis_id, dimension, metric, value, threshold, reason, suggestion) VALUES ('f79faaba-fc91-44fe-9312-3814fbc6521d', 'a4c725f7-6fe1-4232-814b-74523f7eb923', '工作满意度', 'bartlett_p', 1, 0.05, 'Bartlett 球形检验 p = 1.0（不显著），表明相关矩阵为单位矩阵，即变量间完全独立。这通常是数据被严重扭曲的信号：可能所有条目取值完全相同、被误设为常量、或反向题未反转导致正负相关抵消后整体相关为零。', '1. 确认数据是否已正确导入且数值范围合理；2. 绘制散点图矩阵，检查是否存在非线性关系或异常值；3. 若为定性数据（如分类变量），需改用多分格相关矩阵代替 Pearson 相关；4. 在反转反向题后重新运行检验。');
INSERT INTO diagnosis_issues (id, diagnosis_id, dimension, metric, value, threshold, reason, suggestion) VALUES ('964abbf7-a5c7-431d-84c5-7aec45ded0c7', 'a4c725f7-6fe1-4232-814b-74523f7eb923', '人际关系', 'alpha', 0, 0.7, 'Cronbach''s α 为 0.0，表明该维度内各条目之间完全不存在正相关，甚至可能因反向题未反转导致负相关被抵消。同时不排除数据录入错误、条目方差为零（如所有被试回答完全相同）或样本量过小（如 < 5）导致信度无法计算。', '1. 检查原始数据：确认该维度所有条目是否存在变异（即标准差 > 0）；2. 核对反向题的编码是否已正确反转（原值 → 6-原值）；3. 若样本量 < 30，建议补充样本至至少 50 人；4. 重算信度前，删除缺失值或常数条目。');
INSERT INTO diagnosis_issues (id, diagnosis_id, dimension, metric, value, threshold, reason, suggestion) VALUES ('a67a74df-7082-4d93-a405-6625d01c2b68', 'a4c725f7-6fe1-4232-814b-74523f7eb923', '人际关系', 'kmo', 0, 0.5, 'KMO 为 0.0，说明变量间偏相关系数平方和远大于简单相关系数平方和，数据完全不适合做因子分析。常见原因包括：变量间几乎无线性相关（可能因反向题未反转导致符号错乱）、条目方差为零、或样本量极低（< 样本数 < 变量数）。', '1. 计算各条目间 Pearson 相关矩阵，若多数相关系数 < 0.1，需检查数据质量；2. 确保所有条目为非定值且量尺一致（如均使用 1-5 Likert）；3. 增加样本量至条目数的 5-10 倍；4. 在反转反向题后重新计算 KMO。');
